# Seq2Seq概念: 编码→压缩→解码
class Encoder(nn.Module):
    def __init__(self):
        self.rnn = nn.LSTM(64, 256)
    def forward(self, x):
        _, (h, c) = self.rnn(x)  # 最后时间步的隐藏状态=上下文向量
        return h, c

class Decoder(nn.Module):
    def __init__(self):
        self.rnn = nn.LSTM(64, 256)
        self.out = nn.Linear(256, 20)  # 20种氨基酸
    def forward(self, x, h, c):
        out, (h, c) = self.rnn(x, (h, c))
        return self.out(out), h, c

