import numpy as np
from scipy.spatial.distance import pdist, squareform

# AlphaFold的ML核心: 共进化分析
# MSA (多序列比对) -> 共进化矩阵
msa = np.random.choice([0,1,2,3,4], size=(1000, 50))  # 模拟MSA

# 互信息: I(i,j) = sum_{a,b} p_ij(a,b) * log(p_ij(a,b) / (p_i(a)*p_j(b)))
def mutual_info(msa, n_states=5):
    L = msa.shape[1]
    mi = np.zeros((L, L))
    for i in range(L):
        for j in range(i+1, L):
            p_i = np.bincount(msa[:,i], minlength=n_states) / len(msa)
            p_j = np.bincount(msa[:,j], minlength=n_states) / len(msa)
            joint = np.histogram2d(msa[:,i], msa[:,j], bins=n_states)[0] / len(msa)
            for a in range(n_states):
                for b in range(n_states):
                    if joint[a,b] > 0 and p_i[a]*p_j[b] > 0:
                        mi[i,j] += joint[a,b] * np.log(joint[a,b] / (p_i[a]*p_j[b]))
    return mi + mi.T

import numpy as np

# 基因组语言模型: DNA序列的k-mer表示
seq = 'ATCGATCGATCGATCGATCG'
k = 4

def kmer_frequencies(seq, k):
    '''k-mer频率 -> 基因组特征向量'''
    kmers = {}
    for i in range(len(seq) - k + 1):
        kmer = seq[i:i+k]
        kmers[kmer] = kmers.get(kmer, 0) + 1
    return kmers

