import numpy as np

# RL for molecular optimization
# 状态=分子, 动作=添加/修改原子, 奖励=drug-likeness
class MoleculeEnv:
    def __init__(self):
        self.state = ['C']  # 起始原子
    def step(self, action):
        '''action: 0=add C, 1=add O, 2=add N, 3=terminate'''
        if action == 3:
            reward = self._drug_likeness()
            done = True
        else:
            atom = ['C','O','N'][action]
            self.state.append(atom)
            reward = -0.01  # 每步小惩罚
            done = len(self.state) > 50
        return self.state, reward, done
    def _drug_likeness(self):
        '''简化的drug-likeness评分'''
        return min(1.0, len(self.state)/20) * (0.5 + 0.5*np.random.random())

