import numpy as np

def numerical_derivative(f, x, h=1e-5):
    '''中心差分法求导数'''
    return (f(x + h) - f(x - h)) / (2 * h)

def gradient_descent(f, grad_f, x0, lr=0.01, n_iter=100):
    '''梯度下降优化'''
    x = x0
    path = [x]
    for _ in range(n_iter):
        x = x - lr * grad_f(x)
        path.append(x)
    return np.array(path)

